import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient\(\);

async function main\(\) {
  // --- Exercise stale sweeper logic \(from workspace-cleanup.ts:enqueueStaleWorkspaceCleanup\) ---
  const STALE_TERMINATING_MS = 10 * 60_000;
  const STALE_CREATING_MS = 15 * 60_000;
  const now = Date.now\(\);

  console.log\('=== STALE SWEEPER ==='\);

  // Stale CREATING
  const staleCreating = await prisma.workspace.findMany\({
    where: { status: 'CREATING', updatedAt: { lt: new Date\(now - STALE_CREATING_MS\) } },
    select: { id: true, status: true },
    take: 100,
  }\);
  console.log\('Stale CREATING found:', staleCreating.length\);

  for \(const ws of staleCreating\) {
    await prisma.workspace.update\({
      where: { id: ws.id },
      data: { status: 'TERMINATING', terminationReason: 'stale_creating_reconcile' },
    }\);
    await prisma.workspaceCleanupJob.upsert\({
      where: { workspaceId: ws.id },
      update: { status: 'PENDING', nextAttemptAt: new Date\(\), reasonCode: 'stale_creating_reconcile' },
      create: { workspaceId: ws.id, reasonCode: 'stale_creating_reconcile', status: 'PENDING', nextAttemptAt: new Date\(\) },
    }\);
    console.log\('  Transitioned', ws.id, 'CREATING -> TERMINATING + cleanup job'\);
  }

  // Stale TERMINATING
  const staleTerminating = await prisma.workspace.findMany\({
    where: { status: 'TERMINATING', updatedAt: { lt: new Date\(now - STALE_TERMINATING_MS\) } },
    select: { id: true },
    take: 100,
  }\);
  console.log\('Stale TERMINATING found:', staleTerminating.length\);

  for \(const ws of staleTerminating\) {
    await prisma.workspaceCleanupJob.upsert\({
      where: { workspaceId: ws.id },
      update: { status: 'PENDING', nextAttemptAt: new Date\(\), reasonCode: 'stale_terminating_reconcile' },
      create: { workspaceId: ws.id, reasonCode: 'stale_terminating_reconcile', status: 'PENDING', nextAttemptAt: new Date\(\) },
    }\);
    console.log\('  Enqueued cleanup for', ws.id\);
  }

  // --- Exercise session finalization \(from workspace-cleanup.ts:finalizeUsageSessions\) ---
  console.log\('\\\\n=== SESSION FINALIZATION ==='\);
  const wsWithSessions = 'aaaaaaaa-bbbb-cccc-dddd-eeeeeeee0003';
  const activeSessions = await prisma.usageSession.findMany\({
    where: { workspaceId: wsWithSessions, status: 'RUNNING' },
  }\);
  console.log\('RUNNING sessions on TERMINATING workspace:', activeSessions.length\);

  for \(const session of activeSessions\) {
    const endTime = new Date\(\);
    const totalSeconds = Math.max\(0, Math.ceil\(\(endTime.getTime\(\) - session.startTime.getTime\(\)\) / 1000\)\);
    const billedCents = Math.ceil\(\(totalSeconds * session.pricePerHourCents\) / 3600\);

    try {
      await prisma.\\$transaction\([
        prisma.usageSession.update\({
          where: { id: session.id, status: 'RUNNING' },
          data: { endTime, totalSeconds, billedSeconds: totalSeconds, billedCents, status: 'ENDED' },
        }\),
        prisma.workspaceMeterEventOutbox.upsert\({
          where: { usageSessionId: session.id },
          update: { valueSeconds: totalSeconds, status: 'PENDING', nextAttemptAt: new Date\(\) },
          create: { usageSessionId: session.id, userId: session.userId, workspaceId: wsWithSessions, valueSeconds: totalSeconds, status: 'PENDING', nextAttemptAt: new Date\(\) },
        }\),
      ]\);
      console.log\('  Closed session', session.id, '- billedCents:', billedCents, 'totalSeconds:', totalSeconds\);
    } catch \(err: any\) {
      if \(err?.code === 'P2025'\) console.log\('  Session already closed \(P2025\)'\);
      else throw err;
    }
  }

  // --- Exercise stale endpoint cleanup \(gateway reconcileLeases pattern\) ---
  console.log\('\\\\n=== STALE ENDPOINT CLEANUP ==='\);
  const staleEndpoints = await prisma.workspaceEndpoint.findMany\({
    where: { releasedAt: null, workspace: { status: { in: ['TERMINATED', 'FAILED'] } } },
  }\);
  console.log\('Stale endpoints found:', staleEndpoints.length\);

  for \(const ep of staleEndpoints\) {
    await prisma.workspaceEndpoint.update\({
      where: { id: ep.id },
      data: { releasedAt: new Date\(\) },
    }\);
    console.log\('  Released endpoint', ep.id, 'for workspace', ep.workspaceId\);
  }

  // --- Final state verification ---
  console.log\('\\\\n=== FINAL STATE ==='\);
  const remainingRunning = await prisma.usageSession.count\({
    where: { status: 'RUNNING', workspace: { region: 'cleanup-test' } },
  }\);
  console.log\('Remaining RUNNING sessions on cleanup-test:', remainingRunning\);

  const remainingOrphanEndpoints = await prisma.workspaceEndpoint.count\({
    where: { releasedAt: null, workspace: { status: { in: ['TERMINATED', 'FAILED'] }, region: 'cleanup-test' } },
  }\);
  console.log\('Remaining orphan endpoints:', remainingOrphanEndpoints\);

  const cleanupJobs = await prisma.workspaceCleanupJob.findMany\({
    where: { workspace: { region: 'cleanup-test' } },
    select: { workspaceId: true, status: true, reasonCode: true },
  }\);
  console.log\('Cleanup jobs created:', cleanupJobs.length\);
  for \(const j of cleanupJobs\) {
    console.log\('  ', j.workspaceId, j.status, j.reasonCode\);
  }

  const endedWithOutbox = await prisma.usageSession.findMany\({
    where: { status: 'ENDED', workspace: { region: 'cleanup-test' } },
    include: { meterOutbox: true },
  }\);
  console.log\('ENDED sessions with outbox:', endedWithOutbox.length\);
  for \(const s of endedWithOutbox\) {
    console.log\('  session', s.id, '- outbox:', s.meterOutbox ? 'YES' : 'MISSING', '- billedCents:', s.billedCents\);
  }

  await prisma.\\$disconnect\(\);
}

main\(\).catch\(e => { console.error\(e\); process.exit\(1\); }\);
